sql:
SELECT COUNT(*) AS total_not_interested_drops
FROM lead_drops
WHERE drop_reason = 'Not Interested';

SELECT DISTINCT drop_reason
FROM lead_drops
ORDER BY drop_reason;

SELECT city_tier_name
FROM city_tiers
WHERE city_tier_description IS NOT NULL;

external_knowledge:
- 'crossed the bridge of application completion' refers to the condition where the application status is 'completed' in the application_completions table;
- 'left footprints in at least one of the interaction islands' refers to having at least one interaction in any of the assistance, career, payment, social, or syllabus interactions tables;
- 'total adventures' refers to the total number of interactions a customer has had across all categories.

sql:
SELECT city_tier_name
FROM city_tiers
ORDER BY city_tier_name ASC;

SELECT city_tier_name, city_tier_description
FROM city_tiers
ORDER BY city_tier_id;
